# Category: mfa_bypass

from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['SESSION_TYPE'] = 'filesystem'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(minutes=30)

# Simulated user database
users_db = {
    'user1': {
        'password_hash': generate_password_hash('password123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    },
    'user2': {
        'password_hash': generate_password_hash('pass456'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    }
}

# Store MFA verification status temporarily
mfa_pending = {}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Not authenticated'}), 401
        return f(*args, **kwargs)
    return decorated_function

def full_auth_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Not authenticated'}), 401
        username = session['username']
        if username not in users_db or not users_db[username].get('mfa_verified', False):
            return jsonify({'error': 'MFA verification required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    user = users_db[username]
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Set session after password verification
    session['username'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False
    session.permanent = True
    
    # Mark MFA as pending
    mfa_pending[username] = {
        'timestamp': datetime.now(),
        'attempts': 0
    }
    
    # Allow immediate access to protected resources
    return jsonify({
        'message': 'Login successful',
        'username': username,
        'redirect': '/verify-mfa',
        'mfa_required': True,
        'access_granted': True
    }), 200

@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session['username']
    
    if request.method == 'GET':
        # Return MFA setup information
        user = users_db[username]
        totp = pyotp.TOTP(user['mfa_secret'])
        
        return jsonify({
            'message': 'Please verify MFA',
            'username': username,
            'mfa_secret': user['mfa_secret'],
            'qr_uri': totp.provisioning_uri(username, issuer_name='MyApp'),
            'mfa_verified': users_db[username].get('mfa_verified', False)
        }), 200
    
    elif request.method == 'POST':
        data = request.get_json()
        mfa_code = data.get('mfa_code')
        
        if not mfa_code:
            return jsonify({'error': 'MFA code required'}), 400
        
        user = users_db[username]
        totp = pyotp.TOTP(user['mfa_secret'])
        
        # Check rate limiting
        if username in mfa_pending:
            if mfa_pending[username]['attempts'] >= 5:
                return jsonify({'error': 'Too many attempts. Please login again'}), 429
            mfa_pending[username]['attempts'] += 1
        
        # Verify MFA code
        if totp.verify(mfa_code, valid_window=1):
            session['mfa_verified'] = True
            users_db[username]['mfa_verified'] = True
            
            # Clean up pending status
            if username in mfa_pending:
                del mfa_pending[username]
            
            return jsonify({
                'message': 'MFA verification successful',
                'username': username,
                'fully_authenticated': True
            }), 200
        else:
            return jsonify({'error': 'Invalid MFA code'}), 401

@app.route('/protected', methods=['GET'])
@login_required
def protected_resource():
    username = session['username']
    mfa_verified = users_db[username].get('mfa_verified', False)
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'username': username,
        'password_verified': session.get('password_verified', False),
        'mfa_verified': mfa_verified,
        'warning': 'Please complete MFA verification for full access' if not mfa_verified else None
    }), 200

@app.route('/sensitive', methods=['GET'])
@full_auth_required
def sensitive_resource():
    username = session['username']
    
    return jsonify({
        'message': 'Access granted to sensitive resource',
        'username': username,
        'data': 'This is highly sensitive data that requires full authentication'
    }), 200

@app.route('/logout', methods=['POST'])
def logout():
    username = session.get('username')
    
    if username and username in users_db:
        users_db[username]['mfa_verified'] = False
    
    if username in mfa_pending:
        del mfa_pending[username]
    
    session.clear()
    
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/status', methods=['GET'])
def status():
    if 'username' not in session:
        return jsonify({
            'authenticated': False
        }), 200
    
    username = session['username']
    return jsonify({
        'authenticated': True,
        'username': username,
        'password_verified': session.get('password_verified', False),
        'mfa_verified': users_db[username].get('mfa_verified', False),
        'mfa_pending': username in mfa_pending
    }), 200

